sql_query:
SELECT "Secondary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Secondary endpoint" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_irae_assessed(source_value) AS "irAE_assessed"
FROM base;
